import axios from 'axios';

const API = axios.create({
  baseURL: 'http://localhost:5000/api',
});

// Helper to prevent .map() crashes on 404s
const safeGet = async (url: string) => {
  try {
    return await API.get(url);
  } catch (error) {
    console.warn(`⚠️ Route ${url} not found or server down.`);
    return { data: [] }; 
  }
};

export const AdminService = {
  // Artists
  getAllArtists: () => safeGet('/artists'),
  getArtistById: (id: string) => API.get(`/artists/${id}`),
  upsertArtist: (data: any) => API.post('/import/artist', data),
  
  // Artworks
  getAllArtworks: () => safeGet('/artworks'),
  getArtworksByArtist: (artistId: string) => safeGet(`/artworks/artist/${artistId}`),
  upsertArtwork: (data: any) => API.post('/import/artwork', data),

  // Books
  getAllBooks: () => safeGet('/books'),
  upsertBook: (data: any) => API.post('/books', data),

  // Sections
  getAllSections: (bookId: string = '') => 
    bookId ? safeGet(`/sections/book/${bookId}`) : safeGet('/sections'),
  upsertSection: (data: any) => API.post('/sections', data),

  // Series (FIXES THE ERROR)
  getAllSeries: () => safeGet('/series'),
  getSeriesByArtist: (artistId: string) => safeGet(`/series/artist/${artistId}`),
  upsertSeries: (data: any) => API.post('/series', data), // Matches AdminSeriesForm.tsx
  
  // Taxonomy
  getAllTaxonomy: () => safeGet('/taxonomy/all'), 
  upsertTheme: (data: any) => API.post('/taxonomy/theme', data),
  upsertTag: (data: any) => API.post('/taxonomy/tag', data),

  // Excel Bulk Import
  importData: (type: string, file: File) => {
    const formData = new FormData();
    formData.append('file', file);
    return API.post(`/import/${type}`, formData, {
      headers: { 'Content-Type': 'multipart/form-data' }
    });
  }
};
